programRules.condition:
(
  !#{NeoIPC BSI - no positive culture}
  &&
  (
    d2:hasValue(#{NeoIPC BSI Pathogen 1 value})
    ||
    d2:hasValue(#{NeoIPC BSI Pathogen 2 value})
    ||
    d2:hasValue(#{NeoIPC BSI Pathogen 3 value})
  )
  &&
  (
    !#{NeoIPC BSI Pathogen 1 is recognized pathogen}
    &&
    !#{NeoIPC BSI Pathogen 2 is recognized pathogen}
    &&
    !#{NeoIPC BSI Pathogen 3 is recognized pathogen}
  )
)
&&
(
  (
    !#{NeoIPC BSI Pathogen 1 recovered multiple times value}
    &&
    !#{NeoIPC BSI Pathogen 2 recovered multiple times value}
    &&
    !#{NeoIPC BSI Pathogen 3 recovered multiple times value}
    &&
    !#{NeoIPC BSI - Antibiotic treatment}
  )
  &&
  (
    (#{NeoIPC BSI Common commensal once clinical findings count} < 2)
    ||
    (#{NeoIPC BSI Common commensal once laboratory findings count} < 1)
  )
)

#{NeoIPC SSI Infection type value} == 2
&& !#{NeoIPC SSI Purulent drainage deep incision value}
&& !#{NeoIPC SSI Abscess deep incision value}
&& !(
  #{NeoIPC SSI Deep incision dehisces value}
  &&
  #{NeoIPC SSI Organisms identified from deep tissue of incision value} != 0
  && (
    #{NeoIPC SSI Fever value}
    ||
    #{NeoIPC SSI Localized pain deep value}
  )
)

#{NeoIPC SSI Infection type value} == 3
&& !#{NeoIPC SSI Purulent drainage drain value}
&& #{NeoIPC SSI Organisms identified from organ space fluid tissue value} < 1
&& !#{NeoIPC SSI Abscess organ space value}

#{NeoIPC SSI Infection type value} == 1
&& !#{NeoIPC SSI Purulent drainage superficial incision value}
&& #{NeoIPC SSI Organisms identified from superficial incision value}  != 1
&& !#{NeoIPC SSI Diagnosis superficial by physician value}
&& !(
  #{NeoIPC SSI Superficial incision opened value}
  &&
  #{NeoIPC SSI Organisms identified from superficial incision value}  == -1
  && (
    #{NeoIPC SSI Localized pain superficial value}
    ||
    #{NeoIPC SSI Localized swelling value}
    ||
    #{NeoIPC SSI Localized erythema value}
    ||
    #{NeoIPC SSI Localized heat value}
  )
)
